choose.when:
SELECT d.* FROM (
    SELECT @ids AS _ids,
( SELECT @ids := GROUP_CONCAT( hx_number ) FROM sys_hx6_tree WHERE FIND_IN_SET( parent_hx_number, @ids ) ) AS cids,
@l := @l + 1 AS LEVEL
FROM sys_hx6_tree,
( SELECT @ids := ( SELECT pu.hx_number FROM sys_hx6_tree pu WHERE pu.hx_number = '${hxNumber}' ), @l := 0 ) b
WHERE
@ids IS NOT NULL
) dd,sys_hx6_tree d
WHERE FIND_IN_SET( d.hx_number, dd._ids )
